import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val parent = Array.tabulate((c + 1).toInt)(i => i)
  val minId = Array.tabulate((c + 1).toInt)(i => i)

  def find(u: Int): Int = {
    if (parent(u) != u) {
      parent(u) = find(parent(u))
    }
    parent(u)
  }

  def union(u: Int, v: Int): Unit = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU != rootV) {
      if (rootU < rootV) {
        parent(rootV) = rootU
        minId(rootU) = math.min(minId(rootU), minId(rootV))
      } else {
        parent(rootU) = rootV
        minId(rootV) = math.min(minId(rootV), minId(rootU))
      }
    }
  }

  connections.foreach { case Array(u, v) =>
    union(u.toInt, v.toInt)
  }

  val online = Array.fill((c + 1).toInt)(true)
  val result = mutable.ArrayBuffer[Long]()
  val componentMinOnline = mutable.Map[Int, mutable.TreeSet[Int]]()

  for (i <- 1 to c.toInt) {
    val root = find(i)
    componentMinOnline.getOrElseUpdate(root, mutable.TreeSet[Int]()).add(i)
  }

  queries.foreach { case Array(queryType, x) =>
    val xInt = x.toInt
    if (queryType == 1) {
      if (online(xInt)) {
        result += x
      } else {
        val root = find(xInt)
        val onlineSet = componentMinOnline.getOrElse(root, mutable.TreeSet[Int]())
        if (onlineSet.isEmpty) {
          result += -1
        } else {
          result += onlineSet.head.toLong
        }
      }
    } else if (queryType == 2) {
      if (online(xInt)) {
        val root = find(xInt)
        componentMinOnline(root).remove(xInt)
        online(xInt) = false
      }
    }
  }

  result.toArray
}
```

