import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val parent = Array.ofDim[Long](c.toInt + 1)
  val minNode = Array.ofDim[Long](c.toInt + 1)

  for (i <- 1 to c.toInt) {
    parent(i) = i
    minNode(i) = i
  }

  def find(u: Long): Long = {
    if (parent(u.toInt) != u) {
      parent(u.toInt) = find(parent(u.toInt))
    }
    parent(u.toInt)
  }

  def union(u: Long, v: Long): Unit = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU != rootV) {
      if (rootU < rootV) {
        parent(rootV.toInt) = rootU
        minNode(rootU.toInt) = math.min(minNode(rootU.toInt), minNode(rootV.toInt))
      } else {
        parent(rootU.toInt) = rootV
        minNode(rootV.toInt) = math.min(minNode(rootV.toInt), minNode(rootU.toInt))
      }
    }
  }

  connections.foreach { case Array(u, v) => union(u, v) }

  val online = Array.ofDim[Boolean](c.toInt + 1)
  for (i <- 1 to c.toInt) online(i) = true

  val componentMinOnline = mutable.HashMap[Long, mutable.TreeSet[Long]]()

  for (i <- 1 to c.toInt) {
    val root = find(i)
    componentMinOnline.getOrElseUpdate(root, mutable.TreeSet[Long]()).add(i)
  }

  val result = mutable.ArrayBuffer[Long]()

  queries.foreach { query =>
    val queryType = query(0)
    val x = query(1)

    if (queryType == 1) {
      if (online(x.toInt)) {
        result += x
      } else {
        val root = find(x)
        val onlineNodes = componentMinOnline.getOrElse(root, mutable.TreeSet[Long]())
        if (onlineNodes.isEmpty) {
          result += -1
        } else {
          result += onlineNodes.head
        }
      }
    } else if (queryType == 2) {
      if (online(x.toInt)) {
        online(x.toInt) = false
        val root = find(x)
        componentMinOnline.getOrElseUpdate(root, mutable.TreeSet[Long]()).remove(x)
      }
    }
  }

  result.toArray
}
