import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val parent = Array.tabulate(c.toInt + 1)(i => i)
  val minId = Array.tabulate(c.toInt + 1)(i => i)

  def find(u: Int): Int = {
    if (parent(u) != u) {
      parent(u) = find(parent(u))
    }
    parent(u)
  }

  def union(u: Int, v: Int): Unit = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU != rootV) {
      if (rootU < rootV) {
        parent(rootV) = rootU
        minId(rootU) = math.min(minId(rootU), minId(rootV))
      } else {
        parent(rootU) = rootV
        minId(rootV) = math.min(minId(rootV), minId(rootU))
      }
    }
  }

  connections.foreach { case Array(u, v) =>
    union(u.toInt, v.toInt)
  }

  val online = Array.fill(c.toInt + 1)(true)
  val componentMinOnline = mutable.Map[Int, mutable.TreeSet[Int]]()

  for (i <- 1 to c.toInt) {
    val root = find(i)
    componentMinOnline.getOrElseUpdate(root, mutable.TreeSet[Int]()).add(i)
  }

  val result = mutable.ArrayBuffer[Long]()

  queries.foreach { case Array(t, x) =>
    val queryType = t.toInt
    val node = x.toInt
    if (queryType == 1) {
      if (online(node)) {
        result += node
      } else {
        val root = find(node)
        val onlineNodes = componentMinOnline.getOrElse(root, mutable.TreeSet[Int]())
        if (onlineNodes.isEmpty) {
          result += -1
        } else {
          result += onlineNodes.head
        }
      }
    } else if (queryType == 2) {
      if (online(node)) {
        online(node) = false
        val root = find(node)
        componentMinOnline.get(root).foreach { set =>
          set.remove(node)
        }
      }
    }
  }

  result.toArray
}
